use std::collections::VecDeque;

struct SlidingWindowAnomalyDetector {
    window_size: usize,
    data_queue: VecDeque<f64>,
}

impl SlidingWindowAnomalyDetector {
    fn new(window_size: usize) -> Self {
        SlidingWindowAnomalyDetector {
            window_size,
            data_queue: VecDeque::with_capacity(window_size),
        }
    }

    fn process_reading(&mut self, reading: f64) -> Option<f64> {
        if self.data_queue.len() < self.window_size / 2 {
            self.data_queue.push_back(reading);
            return None;
        }

        let mean = self.calculate_mean();
        let std_dev = self.calculate_std_dev(mean);

        if std_dev == 0.0 {
            return None;
        }

        let z_score = (reading - mean).abs() / std_dev;

        self.data_queue.push_back(reading);
        if self.data_queue.len() > self.window_size {
            self.data_queue.pop_front();
        }

        let threshold = 3.0;
        if z_score > threshold {
            Some(z_score)
        } else {
            None
        }
    }

    fn calculate_mean(&self) -> f64 {
        let sum: f64 = self.data_queue.iter().sum();
        sum / (self.data_queue.len() as f64)
    }

    fn calculate_std_dev(&self, mean: f64) -> f64 {
        let variance_sum: f64 = self.data_queue.iter().map(|&val| (val - mean).powi(2)).sum();
        let count = self.data_queue.len() as f64;
        if count <= 1.0 {
            return 0.0;
        }
        (variance_sum / (count - 1.0)).sqrt()
    }
}

fn main() {
    let mut detector = SlidingWindowAnomalyDetector::new(10);
    let readings = vec![10.0, 10.5, 9.8, 11.2, 10.1, 10.3, 10.7, 10.0, 10.4, 11.0, 25.0, 10.6];

    for &reading in readings.iter() {
        match detector.process_reading(reading) {
            Some(score) => println!("Anomaly detected! Z-Score: {:.2}", score),
            None => println!("Reading processed normally."),
        }
    }
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};

struct Record {
    id: u32,
    name: String,
    value: f64,
}

fn read_data_from_file(filename: &str) -> io::Result<Vec<Record>> {
    let mut file = File::open(filename)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    let lines: Vec<&str> = contents.trim().lines().collect();
    let mut records = Vec::new();

    for (i, line) in lines.iter().enumerate() {
        if i == 0 { continue; }
        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() < 3 {
            continue;
        }

        let id_result = parts[0].trim().parse::<u32>();
        let value_result = parts[2].trim().parse::<f64>();

        if let (Ok(id), Ok(value)) = (id_result, value_result) {
            records.push(Record {
                id: id,
                name: parts[1].trim().to_string(),
                value: value,
            });
        }
    }
    Ok(records)
}

fn main() -> io::Result<()> {
    let file_path = "sample_data.txt";
    std::fs::write(file_path, "id,name,valuen1,Alice Dupont,3.14n2,Bob O'Malley,9.81n3,François-Jean,1.0n")?;

    match read_data_from_file(file_path) {
        Ok(records) => {
            let mut map: HashMap<String, Record> = HashMap::new();
            for record in records {
                map.insert(record.name.clone(), record);
            }
            println!("Successfully processed {} records.", map.len());
        },
        Err(e) => {
            eprintln!("Error reading file: {}", e);
        }
    }
    Ok(())
}

