        }
    }
}

use std::collections::{HashMap, HashSet};

#[derive(Clone)]
struct EventRecord {
    id: String,
    timestamp: u64,
    data: String,
}

fn process_event_stream(logs: Vec<EventRecord>) -> HashMap<String, Vec<String>> {
    let mut seen_ids = HashSet::new();
    let mut grouped_data: HashMap<String, Vec<String>> = HashMap::new();

    for record in logs.iter() {
        if !seen_ids.contains(&record.id) {
            seen_ids.insert(record.id.clone());
            grouped_data.entry(record.id.clone()).or_default().push(format!("Initial event for {}", record.data));
        } else if !record.data.is_empty() {
            let entry = grouped_data.get_mut(&record.id);
            if let Some(events) = entry { 
                events.push(format!("Updated state with data: {}", record.data));
            }
        }
    }
    grouped_data
}

use std::collections::HashMap;
use std::io::{self, Write};

struct RedirectMap {
    mappings: HashMap<String, String>,
}

impl RedirectMap {
    fn new() -> Self {
        RedirectMap { mappings: HashMap::new() }
    }

    fn add_mapping(&mut self, old_path: &str, new_location: &str) {
        self.mappings.insert(old_path.to_string(), new_location.to_string());
    }

    fn find_redirect(&self, requested_uri: &str) -> Option<&String> {
        let parts: Vec<&str> = requested_uri.split('/').collect();
        let combined_path = parts.join("/");
        self.mappings.get(&combined_path)
    }
}

fn main() -> io::Result<()> {
    let mut proxy_map = RedirectMap::new();
    proxy_map.add_mapping("/old-homepage", "/v2/landing");
    proxy_map.add_mapping("/api/v1/userinfo", "/users/details");

    let test_uris = vec![
        "http://example.com/old-homepage/profile",
        "http://example.com/api/v1/userinfo?id=123"
    ];

    for uri in test_uris {
        println!("nProcessing URI: {}", uri);
        if let Some(redirect) = proxy_map.find_redirect(uri) {
            let status = "302 Found";
            writeln!(io::stdout(), "  -> Detected redirect to: {}", redirect)?; 
            println!("  -> Set HTTP Status: {}", status);
        } else {
            let status = "200 OK";
            writeln!(io::stdout(), "  -> No known redirect. Serving content for path.")?; 
            println!("  -> Set HTTP Status: {}", status);
        }
    }
    Ok(())
}
